import { describe, it } from "vitest";

// Unit-level tests exercise runScenario directly. CLI-level tests at the
// bottom spawn `tsx src/cli.ts` and verify the stdin/stdout/exit-code
// surface end-to-end. See example-mapping/claim-office.md for the
// shared spec, field-name contract, and per-test rationale.

describe("MHPCO Claim Office — quote pricing", () => {
  it.todo(
    "empty items quote: newcomer with no items → premium 5 G (processing fee only)",
  );

  it.todo(
    "single plain amulet, yearsWithMHPCO 0 → premium 71 G (60 base + 6 first-insurance + 5 fee)",
  );

  it.todo(
    "single plain sword, yearsWithMHPCO 0 → premium 115 G (100 base + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "newcomer with cursed sword (steel, enchantment 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "newcomer with plain sword at exactly enchantment 5 → premium 145 G (100 base + 30 high-enchantment + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "newcomer with plain sword at enchantment 4 (below threshold) → premium 115 G (no high-enchantment surcharge)",
  );

  it.todo(
    "newcomer with cursed sword at exactly enchantment 5 → premium 195 G (100 base + 50 curse + 30 high-ench + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "long-standing customer (yearsWithMHPCO 3), single plain sword, only quote → premium 95 G (100 base + 10 first-insurance − 20 loyalty + 5 fee)",
  );

  it.todo(
    "customer at exactly yearsWithMHPCO 2 (loyalty threshold), single plain sword → premium 95 G (loyalty applies)",
  );

  it.todo(
    "long-standing customer's second quote: cursed sword (steel, enchantment 7) → premium 160 G (100 base + 50 curse + 30 high-ench − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)",
  );

  it.todo(
    "multi-item policy, newcomer: cursed sword + plain amulet → premium 231 G (policy base 160 + 50 curse + 16 first-insurance (10% of 160) + 5 fee)",
  );

  it.todo(
    "components: 2 runes, newcomer → premium 60 G (50 base + 5 first-insurance + 5 fee)",
  );

  it.todo(
    "components: 3 runes (block applies), newcomer → premium 71 G (60 block base + 6 first-insurance + 5 fee)",
  );

  it.todo(
    "components: 4 runes (no block — exactly 3 required), newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee)",
  );

  it.todo(
    "components: 7 runes, newcomer → premium 198 G (175 base + 17.5 first + 5 fee = 197.5, rounded UP to 198 in MHPCO's favor)",
  );

  it.todo(
    "components: 2 runes + 1 moonstone (different types, no block), newcomer → premium 88 G (75 base + 7.5 first + 5 fee = 87.5, rounded UP to 88)",
  );

  it.todo(
    "components: 3 runes + 3 moonstones (two separate blocks), newcomer → premium 137 G (120 base + 12 first-insurance + 5 fee)",
  );

  it.todo(
    "two swords in a single quote, newcomer → premium 225 G (200 base + 20 first-insurance + 5 fee)",
  );
});

describe("MHPCO Claim Office — claim payouts", () => {
  it.todo(
    "standard claim: steel sword enchantment 3, damage 500 G → payout 400 G (full reimbursement − 100 G deductible)",
  );

  it.todo(
    "component claim: rune (insurance 250 G), damage 200 G → payout 100 G (full reimbursement − 100 G deductible; no special clause applies to components)",
  );

  it.todo(
    "high-enchantment only: steel sword enchantment 9, damage 1000 G → payout 400 G (50% clause then deductible: 500 − 100)",
  );

  it.todo(
    "dragon-material only: dragon sword enchantment 5, damage 800 G → payout 700 G (full reimbursement then deductible: 800 − 100)",
  );

  it.todo(
    "both clauses apply (50% wins): dragon sword enchantment 9, damage 1000 G → payout 400 G (1000 × 0.5 − 100)",
  );

  it.todo(
    "enchantment exactly 8 threshold: dragon sword enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause kicks in: 500 − 100)",
  );

  it.todo(
    "deductible applied per damage event: dragon attack on sword (damage 500) + amulet (damage 300) → payout 600 G ((500−100) + (300−100))",
  );

  it.todo(
    "two swords insured, claim with two sword damages (steel ench 3): damages 400 + 300 → payout 500 G (each damage handled independently with own deductible)",
  );

  it.todo(
    "payout rounded DOWN in MHPCO's favor: dragon sword enchantment 8, damage 901 G → payout 350 G (901 × 0.5 − 100 = 350.5, rounded down to 350)",
  );
});

describe("MHPCO Claim Office — CLI (stdin/stdout/exit code)", () => {
  it.todo(
    "happy path: schema example scenario on stdin → results JSON on stdout with same length/order, exit code 0",
  );

  it.todo(
    "quote with unknown item type (e.g. broomstick) → CLI exits non-zero, writes error description to stderr, writes no results to stdout",
  );

  it.todo(
    "claim references an item not in the policy (amulet damage on a sword-only policy) → CLI exits non-zero, writes error description to stderr",
  );

  it.todo(
    "claim with damage entry whose itemType is unknown → CLI exits non-zero, writes error description to stderr",
  );

  it.todo(
    "claim with negative damage amount (e.g. amount: -200) → CLI exits non-zero, writes error description to stderr",
  );

  it.todo(
    "claim contains more sword damages than swords insured → CLI exits non-zero, whole claim rejected",
  );

  it.todo(
    "end-to-end scenario with two quotes and a claim referencing policy index 0: follow-up −15 % discount applies to the second quote, results array preserves order and indices",
  );
});
